module.exports = function(RED) {
    "use strict";

    var caps = require("./lib/meo-caps");

    var DEVICE_LIST_TIMEOUT = 5000;

    function MeoGatewayNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;
        node.name = n.name;
        node.host = n.host || "localhost";
        node.port = Number(n.port) || 7070;

        node.apiUrl = function() {
            return "http://" + node.host + ":" + node.port;
        };
    }
    RED.nodes.registerType("meo-gateway", MeoGatewayNode);

    // ── Editor support ────────────────────────────────────────────────
    // The edit dialogs go through here rather than calling the gateway from
    // the browser: the runtime shares a host with the gateway, the browser
    // may not (open the editor from a laptop and "localhost" is the laptop).

    RED.httpAdmin.get("/meo/capabilities", RED.auth.needsPermission("meo-gateway.read"), function(req, res) {
        res.json(caps.list());
    });

    // Host/port come from the query, not from a deployed config node, so the
    // device list works while the gateway node is still being filled in.
    RED.httpAdmin.get("/meo/devices", RED.auth.needsPermission("meo-gateway.read"), function(req, res) {
        var host = req.query.host;
        var port = Number(req.query.port);
        if (!/^[A-Za-z0-9._-]+$/.test(host || "")) {
            res.status(400).json({ message: "invalid gateway host" });
            return;
        }
        if (!(port > 0 && port < 65536)) {
            res.status(400).json({ message: "invalid gateway port" });
            return;
        }
        fetch("http://" + host + ":" + port + "/api/v1/devices", {
            signal: AbortSignal.timeout(DEVICE_LIST_TIMEOUT)
        }).then(function(response) {
            if (!response.ok) {
                throw new Error("gateway returned " + response.status);
            }
            return response.json();
        }).then(function(devices) {
            // Resolve each device's declared ids here so the edit dialog never
            // has to re-implement the kind-from-id-range rule.
            res.json((devices || []).map(function(device) {
                device.caps = caps.commandable(device.capabilities);
                return device;
            }));
        }).catch(function(err) {
            // Unreachable gateway is the common case here, not a server fault.
            res.status(502).json({ message: err.message || "gateway unreachable" });
        });
    });
};
